import { useMemo, useState } from 'react';

import useSWR from 'swr';

import Chip from '@mui/material/Chip';
import Grid from '@mui/material/Grid';
import Stack from '@mui/material/Stack';
import Tab from '@mui/material/Tab';
import Tabs from '@mui/material/Tabs';
import Typography from '@mui/material/Typography';

import MainCard from 'components/MainCard';
import { ErrorState, LoadingState } from 'components/common/PageFeedback';
import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import { actorTypeLabel, roleLabel } from 'features/auth/roles';
import apiClient from 'lib/http/apiClient';
import API_PATHS from 'lib/http/apiPaths';
import extractApiErrorMessage from 'utils/apiError';

const EVENT_FILTERS = [
  {
    key: 'action',
    label: 'Accion',
    options: [
      { value: 'LIST', label: 'Listado' },
      { value: 'RETRIEVE', label: 'Detalle' },
      { value: 'CREATE', label: 'Creacion' },
      { value: 'UPDATE', label: 'Actualizacion' },
      { value: 'DELETE', label: 'Eliminacion' },
      { value: 'CUSTOM', label: 'Custom' }
    ]
  },
  {
    key: 'request_method',
    label: 'Metodo',
    options: [
      { value: 'GET', label: 'GET' },
      { value: 'POST', label: 'POST' },
      { value: 'PUT', label: 'PUT' },
      { value: 'PATCH', label: 'PATCH' },
      { value: 'DELETE', label: 'DELETE' }
    ]
  },
  {
    key: 'is_success',
    label: 'Resultado',
    options: [
      { value: 'true', label: 'Exitoso' },
      { value: 'false', label: 'Error' }
    ]
  }
];

const SESSION_FILTERS = [
  {
    key: 'action',
    label: 'Sesion',
    options: [
      { value: 'LOGIN', label: 'Login' },
      { value: 'LOGOUT', label: 'Logout' },
      { value: 'REFRESH', label: 'Refresh' },
      { value: 'PASSWORD_CHANGE', label: 'Cambio clave' }
    ]
  },
  {
    key: 'success',
    label: 'Resultado',
    options: [
      { value: 'true', label: 'Exitoso' },
      { value: 'false', label: 'Error' }
    ]
  }
];

const fetchSummary = async (url) => {
  const response = await apiClient.get(url);
  return response.data;
};

function formatDate(value) {
  if (!value) return '-';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return '-';
  return parsed.toLocaleString('es-CL');
}

function actionColor(action) {
  if (action === 'DELETE') return 'error';
  if (action === 'CREATE') return 'success';
  if (action === 'UPDATE') return 'warning';
  return 'default';
}

function methodColor(method) {
  if (method === 'POST') return 'success';
  if (method === 'DELETE') return 'error';
  if (method === 'PATCH' || method === 'PUT') return 'warning';
  return 'default';
}

function formatUser(row) {
  if (row.user_name) return row.user_name;
  if (row.user_email) return row.user_email;
  if (row.auth_identifier) return row.auth_identifier;
  return 'Sistema';
}

export default function AuditsPage() {
  const [tab, setTab] = useState('events');

  const { data: summary, error: summaryError, isLoading: summaryLoading } = useSWR(API_PATHS.auditSummary, fetchSummary, {
    revalidateOnFocus: false,
    dedupingInterval: 60000
  });

  const actionsBreakdown = useMemo(() => summary?.actions_breakdown_7d || [], [summary]);
  const methodsBreakdown = useMemo(() => summary?.methods_breakdown_7d || [], [summary]);

  return (
    <Stack sx={{ gap: 2 }}>
      <MainCard title="Auditoria de la aplicacion">
        {summaryLoading ? <LoadingState /> : null}
        {summaryError ? <ErrorState message={extractApiErrorMessage(summaryError, 'No se pudo cargar el resumen de auditoria.')} /> : null}

        {!summaryLoading && !summaryError ? (
          <Grid container spacing={1.5}>
            <Grid size={{ xs: 12, sm: 6, lg: 3 }}>
              <MainCard border title="Eventos 7 dias">
                <Typography variant="h4">{summary?.total_events_7d || 0}</Typography>
              </MainCard>
            </Grid>
            <Grid size={{ xs: 12, sm: 6, lg: 3 }}>
              <MainCard border title="Eventos hoy">
                <Typography variant="h4">{summary?.total_events_today || 0}</Typography>
              </MainCard>
            </Grid>
            <Grid size={{ xs: 12, sm: 6, lg: 3 }}>
              <MainCard border title="Errores 7 dias">
                <Typography variant="h4" color="error.main">
                  {summary?.failed_events_7d || 0}
                </Typography>
              </MainCard>
            </Grid>
            <Grid size={{ xs: 12, sm: 6, lg: 3 }}>
              <MainCard border title="Sesiones 7 dias">
                <Typography variant="h4">{summary?.session_logs_7d || 0}</Typography>
              </MainCard>
            </Grid>
          </Grid>
        ) : null}

        {!summaryLoading && !summaryError ? (
          <Stack direction={{ xs: 'column', md: 'row' }} sx={{ mt: 1.5, gap: 1.5 }}>
            <Stack direction="row" sx={{ gap: 0.75, flexWrap: 'wrap' }}>
              {(actionsBreakdown || []).slice(0, 6).map((item) => (
                <Chip key={`action-${item.action}`} label={`${item.action}: ${item.total}`} size="small" />
              ))}
            </Stack>
            <Stack direction="row" sx={{ gap: 0.75, flexWrap: 'wrap' }}>
              {(methodsBreakdown || []).slice(0, 5).map((item) => (
                <Chip key={`method-${item.request_method}`} label={`${item.request_method}: ${item.total}`} size="small" variant="outlined" />
              ))}
            </Stack>
          </Stack>
        ) : null}
      </MainCard>

      <MainCard content={false}>
        <Tabs value={tab} onChange={(_, next) => setTab(next)}>
          <Tab value="events" label="Acciones y modificaciones" />
          <Tab value="sessions" label="Sesiones de usuario" />
        </Tabs>
      </MainCard>

      {tab === 'events' ? (
        <CrudResourceModule
          title="Bitacora de acciones API"
          path={API_PATHS.auditEvents}
          columns={[
            { key: 'created_at', label: 'Fecha', render: (row) => formatDate(row.created_at) },
            { key: 'user_name', label: 'Usuario', render: (row) => formatUser(row) },
            { key: 'user_role', label: 'Rol', render: (row) => roleLabel(row.user_role) },
            { key: 'user_actor_type', label: 'Perfil', render: (row) => actorTypeLabel(row.user_actor_type) },
            { key: 'action', label: 'Accion', render: (row) => <Chip size="small" color={actionColor(row.action)} label={row.action} /> },
            { key: 'request_method', label: 'Metodo', render: (row) => <Chip size="small" color={methodColor(row.request_method)} label={row.request_method} /> },
            { key: 'resource', label: 'Recurso' },
            { key: 'object_id', label: 'Objeto' },
            { key: 'status_code', label: 'HTTP' },
            {
              key: 'is_success',
              label: 'Resultado',
              render: (row) => <Chip size="small" color={row.is_success ? 'success' : 'error'} label={row.is_success ? 'OK' : 'Error'} />
            },
            { key: 'ip_address', label: 'IP' },
            { key: 'message', label: 'Detalle' }
          ]}
          fields={[]}
          canCreate={false}
          canEdit={false}
          canDelete={false}
          defaultOrdering="-created_at"
          extraFilters={EVENT_FILTERS}
          searchPlaceholder="Buscar por usuario, ruta, recurso o detalle..."
        />
      ) : null}

      {tab === 'sessions' ? (
        <CrudResourceModule
          title="Bitacora de sesiones"
          path={API_PATHS.auditSessions}
          columns={[
            { key: 'created_at', label: 'Fecha', render: (row) => formatDate(row.created_at) },
            { key: 'user_name', label: 'Usuario', render: (row) => formatUser(row) },
            { key: 'user_email', label: 'Email' },
            { key: 'action', label: 'Accion' },
            {
              key: 'success',
              label: 'Resultado',
              render: (row) => <Chip size="small" color={row.success ? 'success' : 'error'} label={row.success ? 'OK' : 'Error'} />
            },
            { key: 'ip_address', label: 'IP' },
            { key: 'auth_identifier', label: 'Identificador login' }
          ]}
          fields={[]}
          canCreate={false}
          canEdit={false}
          canDelete={false}
          defaultOrdering="-created_at"
          extraFilters={SESSION_FILTERS}
          searchPlaceholder="Buscar por usuario, email o IP..."
        />
      ) : null}
    </Stack>
  );
}

